import{_ as a,c as r,o as e,ae as l}from"./chunks/framework.CkyPvWOg.js";const _=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"javascript/事件循环.md","filePath":"javascript/事件循环.md","lastUpdated":1773308029000}'),i={name:"javascript/事件循环.md"};function o(s,t,n,d,h,c){return e(),r("div",null,[...t[0]||(t[0]=[l('<h3 id="js是单线程的" tabindex="-1">js是单线程的 <a class="header-anchor" href="#js是单线程的" aria-label="Permalink to &quot;js是单线程的&quot;">​</a></h3><ul><li>js是单线程的，但是浏览器是多进程的</li><li>js代码执行是在一个单独的线程中，这意味着在同一时间只能执行一个任务</li></ul><h3 id="事件循环" tabindex="-1">事件循环 <a class="header-anchor" href="#事件循环" aria-label="Permalink to &quot;事件循环&quot;">​</a></h3><ul><li>事件循环是浏览器用来处理异步操作的机制</li><li>当一个任务被添加到队列中时，它会等待当前执行的任务完成后再开始执行</li><li>当执行栈空闲时，会反复从任务队列中取出任务执行</li></ul><h3 id="事件循环的执行过程" tabindex="-1">事件循环的执行过程 <a class="header-anchor" href="#事件循环的执行过程" aria-label="Permalink to &quot;事件循环的执行过程&quot;">​</a></h3><ol><li>执行栈（Execution Stack）中有一个全局环境，执行全局代码，同步代码</li><li>遇到异步操作，会在宿主环境中(浏览器)执行，<strong>执行之后</strong>并将回调函数放入<strong>回调队列</strong>中等待。<mark>(即，异步函数<strong>不是立刻</strong>加到任务队列中，而是回调函数达到执行时机后才加入到任务队列中)</mark></li><li>当执行栈空闲时，会反复从任务队列中取出任务执行</li><li>一旦主线程上的<strong>所有同步代码都执行完毕</strong>，事件循环就会检查回调队列是否有待处理的回调函数，如果有的话，会将它们加入到执行栈中进行处理</li><li>这个过程一直重复进行，直到所有的任务都被处理完为止</li></ol><h3 id="宏任务" tabindex="-1">宏任务 <a class="header-anchor" href="#宏任务" aria-label="Permalink to &quot;宏任务&quot;">​</a></h3><ul><li>由**宿主环境（浏览器）**执行的异步代码，比如setTimeout、setInterval等</li></ul><table tabindex="0"><thead><tr><th>宏任务</th><th>执行环境</th></tr></thead><tbody><tr><td>定时器(setTimeout/setInterval)</td><td>浏览器环境</td></tr><tr><td>DOM事件的回调</td><td>浏览器环境</td></tr><tr><td>Ajax请求的回调</td><td>浏览器环境</td></tr></tbody></table><h3 id="微任务" tabindex="-1">微任务 <a class="header-anchor" href="#微任务" aria-label="Permalink to &quot;微任务&quot;">​</a></h3><ul><li>微任务是由<strong>JavaScript引擎</strong>执行的异步代码，比如Promise、MutationObserver等</li></ul><table tabindex="0"><thead><tr><th>微任务</th><th>执行环境</th></tr></thead><tbody><tr><td>Promise的<strong>回调函数</strong>(Promise.then/catch/finally)</td><td>JavaScript引擎</td></tr><tr><td>MutationObserver的<strong>回调函数</strong></td><td>JavaScript引擎</td></tr></tbody></table><h3 id="宏任务和微任务的执行顺序" tabindex="-1">宏任务和微任务的执行顺序 <a class="header-anchor" href="#宏任务和微任务的执行顺序" aria-label="Permalink to &quot;宏任务和微任务的执行顺序&quot;">​</a></h3><ol><li>执行宏任务之前，会把微任务执行完， 在执行一个宏任务（栈中没有就从宏任务队列中取一个执行）</li><li>执行过程遇到异步任务，<strong>执行之后</strong>将回调函数放到任务队列中， 宏任务放到<strong>宏任务队列</strong>，微任务放到<strong>微任务队列</strong></li><li>宏任务执行完毕后，若微任务不为空，就执行<strong>所有</strong>的微任务（依次执行）</li><li>继续下一个宏任务，重复上述过程</li></ol>',14)])])}const b=a(i,[["render",o]]);export{_ as __pageData,b as default};
